import{_ as e}from"./chunks/浏览器渲染原理-CSS解析.19434fcb.js";import{_ as o,o as t,c as a,R as r}from"./chunks/framework.107209bd.js";const b=JSON.parse('{"title":"1. 浏览器解析原理（从地址栏输入URL到网页显示发生了什么？ - 除网络部分）","description":"","frontmatter":{},"headers":[],"relativePath":"面试八股文/浏览器/1.  浏览器解析原理.md","filePath":"面试八股文/浏览器/1.  浏览器解析原理.md","lastUpdated":null}'),s={name:"面试八股文/浏览器/1.  浏览器解析原理.md"},c=r('<h1 id="_1-浏览器解析原理-从地址栏输入url到网页显示发生了什么-除网络部分" tabindex="-1">1. 浏览器解析原理（从地址栏输入URL到网页显示发生了什么？ - 除网络部分） <a class="header-anchor" href="#_1-浏览器解析原理-从地址栏输入url到网页显示发生了什么-除网络部分" aria-label="Permalink to &quot;1. 浏览器解析原理（从地址栏输入URL到网页显示发生了什么？ - 除网络部分）&quot;">​</a></h1><blockquote><p>浏览器的网络线程收到HTML文档后，会产生一个渲染任务，并将其传递给渲染主线程的消息队列。在事件循环机制的作用下，渲染主线程取出消息队列中的渲染任务，开启渲染流程。</p></blockquote><h2 id="解析html-css-js" tabindex="-1">解析HTML/CSS/JS <a class="header-anchor" href="#解析html-css-js" aria-label="Permalink to &quot;解析HTML/CSS/JS&quot;">​</a></h2><p>浏览器会将HTML代码转换为对应的<strong>DOM树（document object model）</strong>，将样式表（浏览器样式、内部、外部样式）转换为<strong>cssom树（css object model）</strong></p><h3 id="解析html过程中遇到css代码怎么办" tabindex="-1">解析HTML过程中遇到CSS代码怎么办？ <a class="header-anchor" href="#解析html过程中遇到css代码怎么办" aria-label="Permalink to &quot;解析HTML过程中遇到CSS代码怎么办？&quot;">​</a></h3><p>为了提高解析效率，浏览器会启动一个预解析器（线程）率先下载和解析CSS</p><img src="'+e+'"><p><strong>CSS代码不会阻塞HTML的解析（因为跑在不同的线程 - 预解析线程）</strong></p><p>解析过程中遇到CSS解析CSS，遇到JS执行JS。为了提高解析效率，浏览器在开始解析前，会启动一个<strong>预解析线程</strong>，率先下载HTML中的外部CSS文件和外部的JS文件</p><blockquote><p>如果主线程解析到<code>link</code>位置，此时外部的CSS文件还没有下载解析好，主线程不会等待，继续解析后续的HTML。这是因为下载和解析CSS的工作是在预解析线程中进行的。<strong>这就是CSS不会阻塞HTML解析的根本原因。</strong></p></blockquote><h3 id="解析过程中遇到js" tabindex="-1">解析过程中遇到JS <a class="header-anchor" href="#解析过程中遇到js" aria-label="Permalink to &quot;解析过程中遇到JS&quot;">​</a></h3><blockquote><p>如果主线程解析到<code>script</code>位置，会停止HTML解析，转而等待JS文件下载好，并将全局代码解析执行完成后，才能继续解析HTML。这是因为JS代码的执行过程可能会修改当前的DOM树，所以DOM树的生成必须暂停，这就是JS会阻塞HTML解析的根本原因</p></blockquote><h2 id="样式计算" tabindex="-1">样式计算 <a class="header-anchor" href="#样式计算" aria-label="Permalink to &quot;样式计算&quot;">​</a></h2><blockquote><p>主线程会遍历得到的DOM树，依次为树中的每个节点计算出它最终的样式（Computed Style）。在这一过程中，很多预设值会变成绝对值，比如<code>red</code>会变成<code>rgb(255,0,0)</code>; 相对单位会变成绝对单位，比如<code>em</code>会变成<code>px</code>。 这一步完成后会得到一颗带有样式的DOM树</p></blockquote>',14),l=[c];function d(n,_,S,i,h,p){return t(),a("div",null,l)}const T=o(s,[["render",d]]);export{b as __pageData,T as default};
